// // This module implements a 2-to-4 decoder with enable. It takes a 2-bit input and generates a 4-bit output, where all bits are set based on the input value.
module decoder_2to4_with_enable(
    input [1:0] data_in,
    input enable,
    output reg [3:0] data_out
);

always @(*) begin
    if (enable) begin
        data_out = 4'b0000;
        data_out[data_in] = 1'b1;
    end else begin
        data_out = 4'b0000;
    end
end

endmodule
